function solve(n, edges, k) {

   // Edge case: if there are no edges, the answer is 0.

   if (edges.length === 0) {

      return 0;

   }

   // Sort the edges by weight.

   edges.sort((a, b) => a[2] - b[2]);

   const maxWeight = edges[edges.length - 1][2];

   // Binary search for the minimal x.

   let low = 0;

   let high = maxWeight;

   let answer = maxWeight;

   function findLastEdgeIndex(target) {

      let left = 0;

      let right = edges.length - 1;

      let res = -1;

      while (left <= right) {

         let mid = Math.floor((left + right) / 2);

         if (edges[mid][2] <= target) {

            res = mid;

            left = mid + 1;

         } else {

            right = mid - 1;

         }

      }

      return res;

   }

   class DSU {

      constructor(size) {

         this.parent = Array(size).fill(0);

         this.rank = Array(size).fill(0);

         this.count = size;

      }

      find(u) {

         if (this.parent[u] !== u) {

            this.parent[u] = this.find(this.parent[u]);

         }

         return this.parent[u];

      }

      union(u, v) {

         let rootU = this.find(u);

         let rootV = this.find(v);

         if (rootU === rootV) return;

         if (this.rank[rootU] < this.rank[rootV]) {

            this.parent[rootU] = rootV;

         } else {

            this.parent[rootV] = rootU;

            if (this.rank[rootU] === this.rank[rootV]) {

               this.rank[rootU]++;

            }

         }

         this.count--;

      }

      getComponents() {

         return this.count;

      }

   }

   while (low <= high) {

      const mid = Math.floor((low + high) / 2);

      const idx = findLastEdgeIndex(mid);

      if (idx === -1) {

         // No edges with weight <= mid. So all nodes are separate.

         const components = n;

         if (components <= k) {

            answer = mid;

            high = mid - 1;

         } else {

            low = mid + 1;

         }

         continue;

      }

      const dsu = new DSU(n);

      for (let i = 0; i <= idx; i++) {

         const u = edges[i][0];

         const v = edges[i][1];

         dsu.union(u, v);

      }

      const components = dsu.getComponents();

      if (components <= k) {

         answer = mid;

         high = mid - 1;

      } else {

         low = mid + 1;

      }

   }

   return answer;

}

